   449→
   450→export const Transcript = (props: TranscriptProps) => {
   451→	const { prompt, promptTokenCount, messages } = props;
   452→
   453→	useEffect(() => {
   454→		const script = document.createElement('script');
   455→		script.type = 'module';
   456→		script.textContent = `import hljs from 'https://esm.sh/highlight.js@11.9.0'; window.hljs = hljs;`;
   457→		document.head.appendChild(script);
   458→
   459→		const style = document.createElement('link');
   460→		style.rel = 'stylesheet';
   461→		style.href = 'https://esm.sh/highlight.js@11.9.0/styles/github-dark-dimmed.css';
   462→		document.head.appendChild(style);
   463→
   464→		const codeStyle = document.createElement('style');
   465→		codeStyle.textContent = 'code * { font-family: monospace !important; }';
   466→		document.head.appendChild(codeStyle);
   467→
   468→		return () => {
   469→			document.head.removeChild(script);
   470→			document.head.removeChild(style);
   471→			document.head.removeChild(codeStyle);
   472→		};
   473→	}, []);
   474→
   475→	const systemTurn = messages.find((t) => t.type === 'system') as SystemMessage | undefined;
   476→	const resultTurn = messages.find((t) => t.type === 'result') as ResultMessage | undefined;
   477→
   478→	const messageTokens = messages.reduce((sum, turn) => sum + (turn.tokenCount || 0), 0);
   479→
   480→	const totalTime = messages.reduce((sum, turn) => sum + (turn.ms || 0), 0);
   481→	const totalMessageTokens = messageTokens;
   482→
   483→	const metadataCards = [];
   484→
   485→	if (systemTurn) {
   486→		metadataCards.push({
   487→			title: 'Agent',
   488→			value: systemTurn.agent || 'N/A',
   489→		});
   490→
   491→		metadataCards.push({
   492→			title: 'Model',
   493→			value: systemTurn.model || 'N/A',
   494→		});
   495→
   496→		if (systemTurn.tools) {
   497→			const mcpTools = systemTurn.tools.filter((t) => t.includes('mcp'));
   498→			metadataCards.push({
   499→				title: 'Available Tools',
   500→				value: systemTurn.tools.length,
   501→				subvalue: mcpTools.length > 0 ? `${mcpTools.length} MCP tools` : 'unknown',
   502→			});
   503→		}
   504→
   505→		if (systemTurn.mcp_servers && systemTurn.mcp_servers.length > 0) {
   506→			const mcpServersHtml =
   507→				'<div style="display: flex; flex-wrap: wrap;">' +
   508→				systemTurn.mcp_servers
   509→					.map(
   510→						(s) =>
   511→							`<div style="display: inline-flex; align-items: center; padding: 0.25rem 0.75rem; background-color: #f3f4f6; border-radius: 9999px; font-size: 0.875rem; margin-right: 0.5rem; margin-bottom: 0.5rem;">
   512→								<span title="${s.status}" style="width: 8px; height: 8px; border-radius: 50%; background-color: ${s.status === 'connected' ? '#10b981' : s.status === 'unknown' ? '#6b7280' : '#ef4444'}; margin-right: 0.5rem;"></span>
   513→								${s.name}
   514→							</div>`,
   515→					)
   516→					.join('') +
   517→				'</div>';
   518→			metadataCards.push({
   519→				title: 'MCP Servers',
   520→				html: mcpServersHtml,
   521→			});
   522→		} else {
   523→			metadataCards.push({
   524→				title: 'MCP Servers',
   525→				value: 'None',
   526→			});
   527→		}
   528→	}
   529→
   530→	if (resultTurn) {
   531→		if (resultTurn.num_turns !== undefined) {
   532→			metadataCards.push({
   533→				title: 'Turns',
   534→				value: resultTurn.num_turns,
   535→			});
   536→		}
   537→
   538→		if (messageTokens > 0) {
   539→			metadataCards.push({
   540→				title: 'Total Message Tokens',
   541→				value: messageTokens.toLocaleString(),
   542→			});
   543→		}
   544→	}
   545→
   546→	const turns = messages.filter((t) => ['assistant', 'user', 'system', 'result'].includes(t.type));
   547→
   548→	const groupedTurns = groupToolCallsWithResults(turns);
   549→
   550→	return (
   551→		<div style={{ fontFamily: 'system-ui, sans-serif', padding: '2rem' }}>
   552→			<h1 style={{ marginTop: 0 }}>Agent Transcript</h1>
   553→
   554→			{metadataCards.length > 0 && (
   555→				<div style={{ marginBottom: '2rem' }}>
   556→					<h2
   557→						style={{
   558→							fontSize: '1.125rem',
   559→							fontWeight: 600,
   560→							marginBottom: '1rem',
   561→						}}
   562→					>
   563→						Metadata
   564→					</h2>
   565→					<div
   566→						style={{
   567→							display: 'grid',
   568→							gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
   569→							gap: '1rem',
   570→						}}
   571→					>
   572→						{metadataCards.map((card, index) => (
   573→							<MetadataCard key={index} {...card} />
   574→						))}
   575→					</div>
   576→				</div>
   577→			)}
   578→
   579→			<h2
   580→				style={{
   581→					fontSize: '1.125rem',
   582→					fontWeight: 600,
   583→					marginBottom: '1rem',
   584→				}}
   585→			>
   586→				Turns
   587→			</h2>
   588→
   589→			{prompt && (
   590→				<Turn
   591→					type="prompt"
   592→					title="User Prompt"
   593→					tokenCount={`${promptTokenCount.toLocaleString()} tokens`}
   594→					percentage={(promptTokenCount / totalMessageTokens) * 100}
   595→				>
   596→					<ContentSection label="Prompt">
   597→						<CodeBlock content={prompt} language="markdown" />
   598→					</ContentSection>
   599→				</Turn>
   600→			)}
   601→
   602→			{groupedTurns.map((group, index) => {
   603→				const isTodoWrite =
   604→					group.toolCall &&
   605→					'message' in group.toolCall &&
   606→					group.toolCall.message?.content?.find(
   607→						(c) => c.type === 'tool_use' && c.name === 'TodoWrite',
   608→					);
   609→
   610→				if (isTodoWrite && 'input' in isTodoWrite && isTodoWrite.input?.todos) {
   611→					return <TodoList key={index} todos={isTodoWrite.input.todos} />;
   612→				}
   613→
   614→				const elements = [];
   615→
   616→				if (index > 0) {
   617→					const currentTurn = group.toolCall || group.turn;
   618→					if (currentTurn) {
   619→						const elapsedMs = currentTurn.ms;
   620→						if (elapsedMs >= 50) {
   621→							const percentage = (elapsedMs / totalTime) * 100;
   622→							elements.push(
   623→								<ElapsedTime
   624→									key={`elapsed-${index}`}
   625→									elapsedMs={elapsedMs}
   626→									percentage={percentage}
   627→								/>,
   628→							);
   629→						}
   630→					}
   631→				}
   632→
   633→				if (group.toolCall && group.toolResult) {
   634→					elements.push(
   635→						<ToolCallGroup
   636→							key={`tool-${index}`}
   637→							toolCall={group.toolCall as AssistantMessage}
   638→							toolResult={group.toolResult as UserMessage}
   639→							totalMessageTokens={totalMessageTokens}
   640→							cwd={systemTurn?.cwd || ''}
   641→						/>,
   642→					);
   643→				} else if (group.turn) {
   644→					elements.push(
   645→						<TurnRenderer
   646→							key={`turn-${index}`}
   647→							turn={group.turn}
   648→							totalMessageTokens={totalMessageTokens}
   649→						/>,
   650→					);
   651→				}
   652→
   653→				return elements;
   654→			})}
   655→		</div>
   656→	);
   657→};
   658→
   659→function groupToolCallsWithResults(turns: TranscriptMessage[]): Array<{
   660→	toolCall?: TranscriptMessage;
   661→	toolResult?: TranscriptMessage;
   662→	turn?: TranscriptMessage;
   663→}> {
   664→	const grouped: Array<{
   665→		toolCall?: TranscriptMessage;
   666→		toolResult?: TranscriptMessage;
   667→		turn?: TranscriptMessage;
   668→	}> = [];
   669→	const usedResultIndices = new Set<number>();
   670→
   671→	for (const [i, turn] of turns.entries()) {
   672→		if (usedResultIndices.has(i)) continue;
   673→
   674→		const toolUseContent =
   675→			turn.type === 'assistant' &&
   676→			'message' in turn &&
   677→			turn.message?.content?.find((c) => c.type === 'tool_use');
   678→
   679→		if (toolUseContent && 'id' in toolUseContent) {
   680→			const toolUseId = toolUseContent.id;
   681→			const resultIndex = turns.findIndex(
   682→				(t, j) =>
   683→					j > i &&
   684→					t.type === 'user' &&
   685→					'message' in t &&
   686→					t.message?.content?.some(
   687→						(c) => c.type === 'tool_result' && 'tool_use_id' in c && c.tool_use_id === toolUseId,
   688→					),
   689→			);
   690→
   691→			if (resultIndex !== -1) {
   692→				grouped.push({ toolCall: turn, toolResult: turns[resultIndex] });
   693→				usedResultIndices.add(resultIndex);
   694→				continue;
   695→			}
   696→		}
   697→
   698→		grouped.push({ turn });
   699→	}
   700→
   701→	return grouped;
   702→}
   703→
   704→const ToolCallGroup = ({
   705→	toolCall,
   706→	toolResult,
   707→	totalMessageTokens,
   708→	cwd,
   709→}: {
   710→	toolCall: AssistantMessage;
   711→	toolResult: UserMessage;
   712→	totalMessageTokens: number;
   713→	cwd: string;
   714→}) => {
   715→	const toolUse = toolCall.message.content.find((c) => c.type === 'tool_use') as ToolUseContent;
   716→	const toolName = toolUse?.name || 'Unknown Tool';
   717→	const isMCP = toolUse?.isMCP;
   718→
   719→	const additionalInfo = extractToolAdditionalInfo(toolUse, toolName, cwd);
   720→
   721→	const totalTokens = (toolCall.tokenCount || 0) + (toolResult.tokenCount || 0);
   722→	const percentage = totalMessageTokens > 0 ? (totalTokens / totalMessageTokens) * 100 : 0;
   723→
   724→	const tokenCountStr =
   725→		toolCall.tokenCount && toolResult.tokenCount
   726→			? `${toolCall.tokenCount.toLocaleString()} + ${toolResult.tokenCount.toLocaleString()} tokens`
   727→			: `${totalTokens.toLocaleString()} tokens`;
   728→
   729→	return (
   730→		<Turn
   731→			type="tool"
   732→			title={toolName}
   733→			subtitle={additionalInfo}
   734→			tokenCount={tokenCountStr}
   735→			percentage={percentage}
   736→			isMCP={isMCP}
   737→		>
   738→			{renderToolInput(toolUse, toolName)}
   739→			{renderToolOutput(toolResult, isMCP)}
   740→		</Turn>
   741→	);
   742→};
   743→
   744→const TurnRenderer = ({
   745→	turn,
   746→	totalMessageTokens,
   747→}: {
   748→	turn: TranscriptMessage;
   749→	totalMessageTokens: number;
   750→}) => {
   751→	const isMCP =
   752→		turn.type === 'assistant' &&
   753→		'message' in turn &&
   754→		turn.message?.content?.some((c) => c.type === 'tool_use' && c.isMCP);
   755→
   756→	const title = getTurnTitle(turn);
   757→	const percentage =
   758→		turn.tokenCount && totalMessageTokens > 0 ? (turn.tokenCount / totalMessageTokens) * 100 : 0;
   759→
   760→	return (
   761→		<Turn
   762→			type={turn.type}
   763→			title={title}
   764→			tokenCount={turn.tokenCount ? `${turn.tokenCount.toLocaleString()} tokens` : undefined}
   765→			percentage={turn.tokenCount ? percentage : undefined}
   766→			isMCP={isMCP}
   767→		>
   768→			{'message' in turn && turn.message?.content
   769→				? renderTurnContent(turn.message.content)
   770→				: renderSystemOrResult(turn)}
   771→		</Turn>
   772→	);
   773→};
   774→
   775→function getTurnTitle(turn: TranscriptMessage): string {
   776→	if (turn.type === 'assistant' && 'message' in turn && turn.message?.content) {
   777→		const toolUse = turn.message.content.find((c) => c.type === 'tool_use');
   778→		if (toolUse && 'name' in toolUse) return toolUse.name;
   779→
   780→		const text = turn.message.content.find((c) => c.type === 'text');
   781→		if (text && 'text' in text) return truncateText(text.text, 80);
   782→	}
   783→
   784→	if (turn.type === 'user' && 'message' in turn && turn.message?.content) {
   785→		const toolResult = turn.message.content.find((c) => c.type === 'tool_result');
   786→		if (toolResult && 'tool_use_id' in toolResult) return `Result: ${toolResult.tool_use_id}`;
   787→	}
   788→
   789→	return 'subtype' in turn && turn.subtype ? turn.subtype : turn.type;
   790→}
   791→
   792→function extractToolAdditionalInfo(
   793→	toolUse: ToolUseContent | undefined,
   794→	toolName: string,
   795→	cwd: string,
   796→): string {
   797→	if (!toolUse?.input) return '';
   798→
   799→	if (['Read', 'Write', 'Edit'].includes(toolName)) {
   800→		const fullPath = toolUse.input.file_path || toolUse.input.path;
   801→		if (fullPath) {
   802→			return cwd && fullPath.startsWith(cwd)
   803→				? fullPath.substring(cwd.length).replace(/^\//, '')
   804→				: fullPath;
   805→		}
   806→	}
   807→
   808→	if (toolName === 'Glob' && toolUse.input.pattern) {
   809→		return toolUse.input.pattern;
   810→	}
   811→
   812→	if (toolName === 'Bash' && toolUse.input.command) {
   813→		const cmd = toolUse.input.command;
   814→		return cmd.length > 80 ? cmd.slice(0, 80) + '...' : cmd;
   815→	}
   816→
   817→	return '';
   818→}
   819→
   820→function renderToolInput(toolUse: ToolUseContent | undefined, toolName: string): React.ReactNode {
   821→	if (!toolUse?.input) return null;
   822→
   823→	if (toolName === 'Write' && toolUse.input.file_path && toolUse.input.content) {
   824→		return (
   825→			<FileContent
   826→				filePath={toolUse.input.file_path}
   827→				content={toolUse.input.content}
   828→				language="typescript"
   829→			/>
   830→		);
   831→	}
   832→
   833→	if (
   834→		toolName === 'Edit' &&
   835→		toolUse.input.file_path &&
   836→		toolUse.input.old_string &&
   837→		toolUse.input.new_string
   838→	) {
   839→		return (
   840→			<FileDiff
   841→				filePath={toolUse.input.file_path}
   842→				oldString={toolUse.input.old_string}
   843→				newString={toolUse.input.new_string}
   844→			/>
   845→		);
   846→	}
   847→
   848→	return (
   849→		<ContentSection label="Input">
   850→			<CodeBlock content={formatJsonWithPreservedWhitespace(toolUse.input)} />
   851→		</ContentSection>
   852→	);
   853→}
   854→
   855→function renderToolOutput(toolResult: UserMessage, isMCP: boolean): React.ReactNode {
   856→	const toolResultContent = toolResult.message.content.find((c) => c.type === 'tool_result');
   857→	if (!toolResultContent) return null;
   858→
   859→	if (isMCP) {
   860→		try {
   861→			const content =
   862→				typeof toolResultContent.content === 'string'
   863→					? JSON.parse(toolResultContent.content)
   864→					: toolResultContent.content;
   865→
   866→			if (Array.isArray(content)) {
   867→				return (
   868→					<ContentSection label="Output">
   869→						<>
   870→							{content.map((item, index) => {
   871→								if (item.type !== 'text' || !item.text) return null;
   872→								return <CodeBlock key={index} content={item.text} isError={item.isError} />;
   873→							})}
   874→						</>
   875→					</ContentSection>
   876→				);
   877→			}
   878→		} catch {
   879→			// Fall through to default rendering
   880→		}
   881→	}
   882→
   883→	return (
   884→		<ContentSection label="Output">
   885→			<CodeBlock
   886→				content={
   887→					typeof toolResultContent.content === 'string'
   888→						? toolResultContent.content
   889→						: JSON.stringify(toolResultContent.content, null, 2)
   890→				}
   891→			/>
   892→		</ContentSection>
   893→	);
   894→}
   895→
   896→function renderTurnContent(
   897→	content: (TextContent | ToolUseContent | ToolResultContent)[],
   898→): React.ReactNode {
   899→	return (
   900→		<>
   901→			{content.map((item, index) => {
   902→				if (item.type === 'text' && 'text' in item) {
   903→					return (
   904→						<ContentSection key={index} label="Text">
   905→							<CodeBlock content={item.text} language="markdown" />
   906→						</ContentSection>
   907→					);
   908→				}
   909→				if (item.type === 'tool_use' && 'name' in item) {
   910→					return (
   911→						<div key={index}>
   912→							<ContentSection label="Tool">
   913→								<code
   914→									style={{
   915→										background: '#f9f9f9',
   916→										padding: '0.25rem 0.5rem',
   917→										borderRadius: '4px',
   918→										fontSize: '0.875rem',
   919→										fontFamily: 'monospace',
   920→									}}
   921→								>
   922→									{item.name}
   923→								</code>
   924→							</ContentSection>
   925→							{'input' in item && item.input && (
   926→								<ContentSection label="Input">
   927→									<CodeBlock content={formatJsonWithPreservedWhitespace(item.input)} />
   928→								</ContentSection>
   929→							)}
   930→						</div>
   931→					);
   932→				}
   933→				if (item.type === 'tool_result' && 'content' in item) {
   934→					return (
   935→						<ContentSection key={index} label="Result">
   936→							<CodeBlock
   937→								content={
   938→									typeof item.content === 'string'
   939→										? item.content
   940→										: JSON.stringify(item.content, null, 2)
   941→								}
   942→							/>
   943→						</ContentSection>
   944→					);
   945→				}
   946→				return null;
   947→			})}
   948→		</>
   949→	);
   950→}
   951→
   952→function renderSystemOrResult(turn: TranscriptMessage): React.ReactNode {
   953→	const data = { ...turn };
   954→	delete (data as any).type;
   955→	delete (data as any).ms;
   956→	delete (data as any).uuid;
   957→	delete (data as any).session_id;
   958→	delete (data as any).parent_tool_use_id;
   959→	delete (data as any).tokenCount;
   960→	delete (data as any).costUSD;
   961→
   962→	return (
   963→		<ContentSection label="Data">
   964→			<CodeBlock content={formatJsonWithPreservedWhitespace(data)} />
   965→		</ContentSection>
   966→	);
   967→}
   968→

