     1→import { useState, useEffect, useRef } from "react";
     2→import { LANGUAGES } from "../languages";
     3→import { useLocalization } from "../hooks/useLocalization";
     4→
     5→export function LanguageSelector() {
     6→  const [showDropdown, setShowDropdown] = useState(false);
     7→  const { setLanguage } = useLocalization();
     8→  const dropdownRef = useRef<HTMLDivElement>(null);
     9→
    10→  const handleClickOutside = (event: MouseEvent) => {
    11→    if (
    12→      dropdownRef.current &&
    13→      !dropdownRef.current.contains(event.target as Node)
    14→    ) {
    15→      setShowDropdown(false);
    16→    }
    17→  };
    18→
    19→  useEffect(() => {
    20→    document.addEventListener("mousedown", handleClickOutside);
    21→    return () => {
    22→      document.removeEventListener("mousedown", handleClickOutside);
    23→    };
    24→  }, []);
    25→
    26→  return (
    27→    <div
    28→      className="relative inline-flex items-center"
    29→      onClick={() => setShowDropdown(!showDropdown)}
    30→      ref={dropdownRef}
    31→    >
    32→      <button className="text-sm text-white/70 hover:text-white transition-colors">
    33→        Language
    34→      </button>
    35→
    36→      {showDropdown && (
    37→        <div className="absolute overflow-y-auto max-h-[205px] py-2 w-40 right-0 top-full mt-1 bg-gray-900 rounded-md shadow-lg">
    38→          {LANGUAGES.sort((a,b) => a.id.localeCompare(b.id)).map((language) => (
