import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import { WikiCard } from './WikiCard';
import type { WikiArticle } from './WikiCard';

const mockArticle: WikiArticle = {
  title: 'Mount Everest',
  displaytitle: 'Mount Everest',
  extract:
    "Mount Everest is Earth's highest mountain above sea level, located in the Mahalangur Himal sub-range of the Himalayas. The China–Nepal border runs across its summit point. Its elevation of 8,848.86 m was most recently established in 2020 by the Chinese and Nepali authorities.",
  pageid: 12345,
  url: 'https://en.wikipedia.org/wiki/Mount_Everest',
  thumbnail: {
    source:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg/800px-Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg',
    width: 800,
    height: 600,
  },
};

const mockArticleNoThumbnail: WikiArticle = {
  title: 'Amazon River',
  displaytitle: 'Amazon River',
  extract:
    "The Amazon River is the largest river in the world by discharge volume of water. It is the largest drainage basin in the world, and accounts for approximately one-fifth of the world's total river flow.",
  pageid: 11111,
  url: 'https://en.wikipedia.org/wiki/Amazon_River',
  thumbnail: null as unknown as WikiArticle['thumbnail'],
};

const meta = {
  component: WikiCard,
} satisfies Meta<typeof WikiCard>;

export default meta;
type Story = StoryObj<typeof meta>;

export const WithThumbnail: Story = {
  args: {
    article: mockArticle,
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('heading', { name: /mount everest/i })).toBeVisible();
    await expect(canvas.getByRole('link', { name: /read more/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /like article/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /share article/i })).toBeVisible();
  },
};

export const WithoutThumbnail: Story = {
  args: {
    article: mockArticleNoThumbnail,
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('heading', { name: /amazon river/i })).toBeVisible();
    await expect(canvas.getByRole('link', { name: /read more/i })).toBeVisible();
  },
};

export const Liked: Story = {
  args: {
    article: mockArticle,
  },
  play: async ({ canvas, userEvent }) => {
    const likeButton = canvas.getByRole('button', { name: /like article/i });
    await expect(likeButton).toBeVisible();
    await userEvent.click(likeButton);
    await expect(likeButton).toHaveClass('bg-red-500');
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import Article from './Article';

const meta = {
  component: Article,
} satisfies Meta<typeof Article>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  args: {
    title: 'Mount Everest',
    content:
      "Mount Everest is Earth's highest mountain above sea level, located in the Mahalangur Himal sub-range of the Himalayas.",
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('heading', { name: /mount everest/i })).toBeVisible();
    await expect(canvas.getByRole('contentinfo')).toBeVisible();
  },
};

export const WithImage: Story = {
  args: {
    title: 'Great Barrier Reef',
    content:
      "The Great Barrier Reef is the world's largest coral reef system, composed of over 2,900 individual reefs and 900 islands.",
    image:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b5/Coral_reef_at_palmyra.jpg/800px-Coral_reef_at_palmyra.jpg',
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('heading', { name: /great barrier reef/i })).toBeVisible();
    await expect(canvas.getByRole('img', { name: /illustration for article/i })).toBeVisible();
  },
};

export const LongContent: Story = {
  args: {
    title: 'Amazon River',
    content: [
      'The Amazon River is the largest river in the world by discharge volume of water.',
      "It is the largest drainage basin in the world, and accounts for approximately one-fifth of the world's total river flow.",
      'The Amazon basin is home to the Amazon rainforest, also known as Amazonia.',
      "The rainforest represents over half of the planet's remaining rainforests, and comprises the largest and most biodiverse tract of tropical rainforest in the world.",
      'More than 30 million people of 350 different ethnic groups live in Amazonia.',
    ].join(' '),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('article')).toBeVisible();
    await expect(canvas.getByRole('heading', { name: /amazon river/i })).toBeVisible();
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import ArticleList from './ArticleList';
import type { ArticleProps } from '../types/ArticleProps';

const sampleArticles: ArticleProps[] = [
  {
    title: 'Mount Everest',
    content:
      "Mount Everest is Earth's highest mountain above sea level, located in the Mahalangur Himal sub-range of the Himalayas.",
  },
  {
    title: 'Great Barrier Reef',
    content:
      "The Great Barrier Reef is the world's largest coral reef system, composed of over 2,900 individual reefs.",
    image:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b5/Coral_reef_at_palmyra.jpg/800px-Coral_reef_at_palmyra.jpg',
  },
  {
    title: 'Amazon River',
    content:
      'The Amazon River is the largest river in the world by discharge volume of water.',
  },
];

const meta = {
  component: ArticleList,
} satisfies Meta<typeof ArticleList>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  args: {
    articles: sampleArticles,
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('navigation', { name: /articles navigation/i })).toBeVisible();
    await expect(canvas.getByRole('heading', { name: /mount everest/i })).toBeVisible();
    await expect(canvas.getByRole('heading', { name: /great barrier reef/i })).toBeVisible();
    await expect(canvas.getByRole('heading', { name: /amazon river/i })).toBeVisible();
  },
};

export const Empty: Story = {
  args: {
    articles: [],
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('navigation', { name: /articles navigation/i })).toBeVisible();
    await expect(canvas.getByRole('list')).toBeVisible();
  },
};

export const WithSelection: Story = {
  args: {
    articles: sampleArticles,
    onArticleSelect: (article: ArticleProps) => console.log('Selected:', article.title),
  },
  play: async ({ canvas, userEvent }) => {
    const firstItem = canvas.getByRole('listitem', { name: /article: mount everest/i });
    await expect(firstItem).toBeVisible();
    await userEvent.click(firstItem);
    await expect(canvas.getByRole('heading', { name: /mount everest/i })).toBeVisible();
  },
};

